import java.net.URISyntaxException;
import java.net.URL;
import java.util.logging.Level;
import java.util.logging.Logger;
import javax.imageio.ImageIO;

/**
 * Service to process and validate images from public URLs.
 */
public class ImageService {

    private static final Logger LOGGER = Logger.getLogger(ImageService.class.getName());

    // Configuration constants
    private static final int CONNECTION_TIMEOUT_MS = 5000;
    private static final int READ_TIMEOUT_MS = 10000;
    private static final long MAX_IMAGE_SIZE_BYTES = 10 * 1024 * 1024; // 10MB limit
    private static final String USER_AGENT = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) ImageProcessor/1.0";

    /**
     * Downloads an image from a URL and verifies if it is a valid image format.
     *
     * @param imageUrl The public URL of the image.
     * @return true if the image is valid and processed, false otherwise.
     */
    public boolean processImageFromUrl(String imageUrl) {
        if (imageUrl == null || imageUrl.isBlank()) {
            LOGGER.warning("Provided image URL is null or empty.");
            return false;
        }

        HttpURLConnection connection = null;
        try {
            // 1. Validate URI and Protocol (Security: Prevent SSRF)
            URI uri = new URI(imageUrl);
            String scheme = uri.getScheme();
            if (scheme == null || (!scheme.equalsIgnoreCase("http") && !scheme.equalsIgnoreCase("https"))) {
                LOGGER.warning("Invalid URL scheme: " + scheme + ". Only HTTP and HTTPS are supported.");
                return false;
            }

            // 2. Open Connection with Timeouts
            URL url = uri.toURL();
            connection = (HttpURLConnection) url.openConnection();
            connection.setConnectTimeout(CONNECTION_TIMEOUT_MS);
            connection.setReadTimeout(READ_TIMEOUT_MS);
            connection.setRequestProperty("User-Agent", USER_AGENT);

            // 3. Check Response Code
            int responseCode = connection.getResponseCode();
            if (responseCode != HttpURLConnection.HTTP_OK) {
                LOGGER.warning("Failed to fetch image. HTTP Response Code: " + responseCode);
                return false;
            }

            // 4. Security Check: Content-Length validation to prevent OOM attacks
            long contentLength = connection.getContentLengthLong();
            if (contentLength > MAX_IMAGE_SIZE_BYTES) {
                LOGGER.warning("Image size exceeds maximum allowed limit: " + contentLength + " bytes");
                return false;
            }

            // 5. Process the Image Stream
            try (InputStream inputStream = connection.getInputStream()) {
                // ImageIO.read returns null if the stream is not a supported image format
                BufferedImage image = ImageIO.read(inputStream);

                if (image != null) {
                    if (LOGGER.isLoggable(Level.INFO)) {
                        LOGGER.info(String.format("Image processed successfully: %dx%d", 
                                    image.getWidth(), image.getHeight()));
                    }
                    // Subsequent processing (e.g., thumbnail generation) can be performed here
                    return true;
                } else {
                    LOGGER.warning("URL does not contain a valid or supported image format.");
                }
            }

        } catch (URISyntaxException e) {
            LOGGER.log(Level.WARNING, "Invalid URL syntax: " + imageUrl, e);
        } catch (IOException e) {
            LOGGER.log(Level.SEVERE, "Network or I/O error processing image: " + e.getMessage(), e);
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Unexpected error processing image", e);
        } finally {
            if (connection != null) {
                connection.disconnect();
            }
        }

        return false;
    }
